import 'package:flutter/cupertino.dart';
import 'package:flutter/material.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

import '../../../../config/theme/colors/theme_colors.dart';
import '../../../../config/theme/theme_typography.dart';
import '../../infrastructure/repositories/contacts_list_repository.dart';

/// Maximum length for custom display names.
const int kMaxDisplayNameLength = 25;

/// Dialog for editing a contact's display name.
///
/// Shows:
/// - Collapsible raw AddressBook data (first, last, organization)
/// - The auto-generated name as a read-only reference (identity anchor)
/// - A text field for entering a custom display name
/// - Clear / Cancel / Save buttons
///
/// ## Usage
///
/// ```dart
/// final result = await showContactNameEditDialog(
///   context: context,
///   ref: ref,
///   contact: contactSummary,
/// );
/// if (result != null) {
///   // User saved a new name (or cleared to use auto-generated)
///   await overlayDb.setParticipantDisplayNameOverride(
///     contact.participantId,
///     result.isEmpty ? null : result,
///   );
/// }
/// ```
Future<String?> showContactNameEditDialog({
  required BuildContext context,
  required WidgetRef ref,
  required ContactSummary contact,
}) {
  return showDialog<String?>(
    context: context,
    barrierDismissible: false,
    builder: (context) => _ContactNameEditDialog(contact: contact),
  );
}

class _ContactNameEditDialog extends ConsumerStatefulWidget {
  const _ContactNameEditDialog({required this.contact});

  final ContactSummary contact;

  @override
  ConsumerState<_ContactNameEditDialog> createState() =>
      _ContactNameEditDialogState();
}

class _ContactNameEditDialogState
    extends ConsumerState<_ContactNameEditDialog> {
  late TextEditingController _controller;
  bool _rawDataExpanded = false;

  @override
  void initState() {
    super.initState();
    // Pre-fill with current display name
    _controller = TextEditingController(text: widget.contact.displayName);
  }

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }

  bool get _hasRawData =>
      widget.contact.givenName != null ||
      widget.contact.familyName != null ||
      widget.contact.organization != null;

  String get _currentText => _controller.text.trim();

  bool get _hasChanges {
    // Changed if different from current display name
    return _currentText != widget.contact.displayName;
  }

  void _handleClear() {
    // Clear means reset to auto-generated name
    _controller.text = widget.contact.autoGeneratedName;
    setState(() {});
  }

  void _handleCancel() {
    Navigator.of(context).pop(null);
  }

  void _handleSave() {
    final value = _currentText;
    // If value equals auto-generated, return empty string to signal "clear override"
    if (value == widget.contact.autoGeneratedName) {
      Navigator.of(context).pop('');
    } else {
      Navigator.of(context).pop(value);
    }
  }

  @override
  Widget build(BuildContext context) {
    ref.watch(themeColorsProvider);
    final colors = ref.read(themeColorsProvider.notifier);
    final typography = ref.watch(themeTypographyProvider);

    return Dialog(
      backgroundColor: colors.surfaces.surfaceRaised,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(12),
        side: BorderSide(color: colors.lines.border, width: 0.5),
      ),
      child: ConstrainedBox(
        constraints: const BoxConstraints(maxWidth: 380, minWidth: 320),
        child: Padding(
          padding: const EdgeInsets.all(20),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              // Title
              Text(
                'Edit Contact Name',
                style: typography.heroTitle,
                textAlign: TextAlign.center,
              ),
              const SizedBox(height: 20),

              // Collapsible raw AddressBook data
              if (_hasRawData) ...[
                _RawDataSection(
                  contact: widget.contact,
                  expanded: _rawDataExpanded,
                  onToggle: () {
                    setState(() => _rawDataExpanded = !_rawDataExpanded);
                  },
                ),
                const SizedBox(height: 16),
              ],

              // Auto-generated name (identity anchor)
              _InfoRow(
                label: 'Auto-generated',
                value: widget.contact.autoGeneratedName,
              ),
              const SizedBox(height: 20),

              // Divider
              Container(height: 1, color: colors.lines.divider),
              const SizedBox(height: 20),

              // Display name text field
              Text('Display Name', style: typography.cassetteCardSectionHeader),
              const SizedBox(height: 8),
              CupertinoTextField(
                controller: _controller,
                placeholder: 'Enter custom name',
                maxLength: kMaxDisplayNameLength,
                style: typography.body,
                padding: const EdgeInsets.symmetric(
                  horizontal: 12,
                  vertical: 10,
                ),
                decoration: BoxDecoration(
                  color: colors.surfaces.control,
                  borderRadius: BorderRadius.circular(8),
                  border: Border.all(
                    color: colors.lines.borderSubtle,
                    width: 0.5,
                  ),
                ),
                onChanged: (_) => setState(() {}),
              ),
              const SizedBox(height: 4),
              Row(
                mainAxisAlignment: MainAxisAlignment.spaceBetween,
                children: [
                  Text(
                    'Name used throughout the app',
                    style: typography.cassetteCardFooter,
                  ),
                  Text(
                    '${_currentText.length}/$kMaxDisplayNameLength',
                    style: typography.cassetteCardFooter.copyWith(
                      color: _currentText.length > kMaxDisplayNameLength
                          ? Colors.red
                          : colors.content.textTertiary,
                    ),
                  ),
                ],
              ),
              const SizedBox(height: 24),

              // Buttons
              Row(
                mainAxisAlignment: MainAxisAlignment.end,
                children: [
                  // Clear button (reset to auto-generated)
                  if (widget.contact.hasDisplayNameOverride ||
                      _currentText != widget.contact.autoGeneratedName) ...[
                    _DialogButton(
                      label: 'Clear',
                      onPressed: _handleClear,
                      isDestructive: true,
                    ),
                    const Spacer(),
                  ],
                  _DialogButton(label: 'Cancel', onPressed: _handleCancel),
                  const SizedBox(width: 12),
                  _DialogButton(
                    label: 'Save',
                    onPressed: _hasChanges ? _handleSave : null,
                    isPrimary: true,
                  ),
                ],
              ),
            ],
          ),
        ),
      ),
    );
  }
}

/// Collapsible section showing raw AddressBook name components.
class _RawDataSection extends ConsumerWidget {
  const _RawDataSection({
    required this.contact,
    required this.expanded,
    required this.onToggle,
  });

  final ContactSummary contact;
  final bool expanded;
  final VoidCallback onToggle;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    ref.watch(themeColorsProvider);
    final colors = ref.read(themeColorsProvider.notifier);
    final typography = ref.watch(themeTypographyProvider);

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // Collapsible header
        GestureDetector(
          onTap: onToggle,
          behavior: HitTestBehavior.opaque,
          child: Row(
            children: [
              Icon(
                expanded
                    ? CupertinoIcons.chevron_down
                    : CupertinoIcons.chevron_right,
                size: 12,
                color: colors.content.textSecondary,
              ),
              const SizedBox(width: 6),
              Text(
                'Imported Name Data',
                style: typography.cassetteCardSectionHeader.copyWith(
                  color: colors.content.textSecondary,
                ),
              ),
            ],
          ),
        ),

        // Expanded content
        if (expanded) ...[
          const SizedBox(height: 12),
          Container(
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: colors.surfaces.control.withValues(alpha: 0.5),
              borderRadius: BorderRadius.circular(8),
            ),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                if (contact.givenName != null)
                  _InfoRow(label: 'First', value: contact.givenName!),
                if (contact.familyName != null)
                  _InfoRow(label: 'Last', value: contact.familyName!),
                if (contact.organization != null)
                  _InfoRow(label: 'Business', value: contact.organization!),
              ],
            ),
          ),
        ],
      ],
    );
  }
}

/// Read-only label + value row.
class _InfoRow extends ConsumerWidget {
  const _InfoRow({required this.label, required this.value});

  final String label;
  final String value;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    ref.watch(themeColorsProvider);
    final colors = ref.read(themeColorsProvider.notifier);
    final typography = ref.watch(themeTypographyProvider);

    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 3),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          SizedBox(
            width: 90,
            child: Text(
              '$label:',
              style: typography.cassetteCardSubtitle.copyWith(
                color: colors.content.textTertiary,
              ),
            ),
          ),
          Expanded(
            child: Text(
              value,
              style: typography.body.copyWith(
                color: colors.content.textPrimary,
              ),
            ),
          ),
        ],
      ),
    );
  }
}

/// Dialog action button.
class _DialogButton extends ConsumerWidget {
  const _DialogButton({
    required this.label,
    required this.onPressed,
    this.isPrimary = false,
    this.isDestructive = false,
  });

  final String label;
  final VoidCallback? onPressed;
  final bool isPrimary;
  final bool isDestructive;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    ref.watch(themeColorsProvider);
    final colors = ref.read(themeColorsProvider.notifier);
    final typography = ref.watch(themeTypographyProvider);

    final isEnabled = onPressed != null;

    Color backgroundColor;
    Color textColor;

    if (!isEnabled) {
      backgroundColor = colors.surfaces.controlMuted;
      textColor = colors.content.textDisabled;
    } else if (isPrimary) {
      backgroundColor = colors.accents.primary;
      textColor = Colors.white;
    } else if (isDestructive) {
      backgroundColor = Colors.transparent;
      textColor = Colors.red;
    } else {
      backgroundColor = colors.surfaces.control;
      textColor = colors.content.textPrimary;
    }

    return GestureDetector(
      onTap: onPressed,
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 8),
        decoration: BoxDecoration(
          color: backgroundColor,
          borderRadius: BorderRadius.circular(6),
          border: isDestructive
              ? Border.all(color: Colors.red.withValues(alpha: 0.3))
              : null,
        ),
        child: Text(
          label,
          style: typography.body.copyWith(
            color: textColor,
            fontWeight: isPrimary ? FontWeight.w600 : FontWeight.w500,
          ),
        ),
      ),
    );
  }
}
